<template><section class="manager"><div class="manager__head"><div><span>CENTRAL DE NOTIFICAÇÕES</span><h2>Fale com sua base</h2></div></div><q-form class="manager__form" @submit.prevent="send"><q-select v-model="form.audience" outlined label="Enviar para" :options="audienceOptions" emit-value map-options /><q-input v-model="form.title" outlined label="Título" /><q-input v-model="form.message" outlined type="textarea" autogrow label="Mensagem" /><q-input v-model="form.actionUrl" outlined label="Link de ação (opcional)" /><q-btn unelevated no-caps class="manager__cta" type="submit" icon="mdi-send" label="Enviar notificação" :loading="loading" /></q-form><h3>Histórico</h3><div class="manager__history"><article v-for="item in history" :key="item._id"><strong>{{item.title}}</strong><span>{{item.message}}</span><small>{{item.recipientType}} · {{new Date(item.createdAt).toLocaleString('pt-BR')}}</small></article></div></section></template>
<script setup>import{onMounted,reactive,ref}from'vue';import{useQuasar}from'quasar';import{api}from'boot/axios';const $q=useQuasar();const token=localStorage.getItem('aito_admin_token');const headers={headers:{Authorization:`Bearer ${token}`}};const loading=ref(false);const history=ref([]);const form=reactive({audience:'user',title:'',message:'',actionUrl:''});const audienceOptions=[{label:'Usuários',value:'user'},{label:'Clientes',value:'customer'},{label:'Afiliados',value:'affiliate'}];async function load(){history.value=(await api.get('/admin/notifications',headers)).data.data||[]}async function send(){loading.value=true;try{const result=await api.post('/admin/notifications',form,headers);$q.notify({type:'positive',message:`Notificação enviada para ${result.data.data.sent} pessoas.`});Object.assign(form,{title:'',message:'',actionUrl:''});await load()}catch(e){$q.notify({type:'negative',message:e.response?.data?.message||'Falha ao enviar.'})}finally{loading.value=false}}onMounted(load)</script><style scoped>.manager{color:#effffb}.manager__head span{color:#8fffee;font-size:.68rem;font-weight:800;letter-spacing:.14em}.manager h2{margin:.3rem 0 1rem}.manager__form{display:grid;max-width:620px;gap:.8rem}.manager__form :deep(.q-field__control){color:#effffb;background:rgba(4,24,25,.8)}.manager__form :deep(.q-field__native),.manager__form :deep(.q-field__label){color:#effffb}.manager__cta{color:#03110f;background:linear-gradient(135deg,#8fffee,#13bc9d);font-weight:800}.manager__history{display:grid;gap:.6rem}.manager__history article{display:grid;gap:.25rem;padding:.8rem;border:1px solid rgba(19,188,157,.2);border-radius:.6rem;background:rgba(4,24,25,.6)}.manager__history span,.manager__history small{color:rgba(239,255,251,.62);font-size:.72rem}</style>
